import*as React from"react";import{setRef}from"../lib/utils.js";class ExternalRef{#element=null;#externRefs=new Set;constructor(e=[]){e.forEach(e=>{e&&this.#externRefs.add(e)})}updateExternRefs(e){e.forEach(e=>{e&&!this.#externRefs.has(e)&&(setRef(this.#element,e),this.#externRefs.add(e))})}get current(){return this.#element}set current(t){this.#element=t,this.#externRefs.forEach(e=>setRef(t,e))}hasOwnProperty(e){return"current"===e}}function useExternRef(...e){const t=React.useRef(null);return null===t.current?t.current=new ExternalRef(e):t.current.updateExternRefs(e),t.current}export{useExternRef};